import { FightingStyle, STYLE_DISPLAY_NAMES } from '@/types/shared.types';
import { getItemById } from '@/data/equipment';
import { audioManager } from '@/lib/AudioManager';
import narrativeContent from '@/data/narrativeContent.json';
import type { NarrativeContent } from '@/types/narrative.types';
import { NarrativeTemplateEngine } from './narrativeTemplateEngine';
import { szToHeight, getWeaponDisplayName, getWeaponType } from './narrativeUtils';
import type { IRNGService } from '@/engine/core/rng/IRNGService';

export interface WarriorIntroData {
  name: string;
  style: FightingStyle;
  weaponId?: string;
  armorId?: string;
  helmId?: string;
  height?: number;
}

/**
 * CombatNarrator - Attack, parry, hit, and defense narration.
 * Handles all combat-related narrative generation.
 */
export class CombatNarrator {
  private constructor() {}
  /**
   * Generates warrior introduction lines.
   */
  static generateWarriorIntro(rng: IRNGService, data: WarriorIntroData, sz?: number): string[] {
    const lines: string[] = [];
    const n = data.name;

    if (sz) lines.push(`${n} is ${szToHeight(sz)}.`);

    const hand =
      rng.next() < 0.85 ? 'right handed' : rng.next() < 0.5 ? 'left handed' : 'ambidextrous';
    lines.push(`${n} is ${hand}.`);

    // Armor & Helm
    const armorItem = data.armorId ? getItemById(data.armorId) : null;
    if (armorItem && armorItem.id !== 'none_armor') {
      const verb =
        NarrativeTemplateEngine.getFromArchive(rng, ['fanfare', 'armor_intro_verbs']) ||
        'is wearing';
      lines.push(`${n} ${verb} ${armorItem.name.toUpperCase()} armor.`);
    } else {
      lines.push(`${n} has chosen to fight without body armor.`);
    }

    const helmItem = data.helmId ? getItemById(data.helmId) : null;
    if (helmItem && helmItem.id !== 'none_helm') {
      lines.push(`And will wear a ${helmItem.name.toUpperCase()}.`);
    }

    // Weapon & Style
    const weaponName = getWeaponDisplayName(data.weaponId);
    if (weaponName === 'OPEN HAND') {
      lines.push(`${n} will fight using his OPEN HAND.`);
    } else {
      const verb =
        NarrativeTemplateEngine.getFromArchive(rng, ['fanfare', 'weapon_intro_verbs']) ||
        'is armed with {{weapon}}';
      lines.push(
        NarrativeTemplateEngine.interpolateTemplate(verb, { attacker: n, weapon: weaponName })
      );
    }

    lines.push(`${n} uses the ${STYLE_DISPLAY_NAMES[data.style]} style.`);
    lines.push(`${n} is well suited to the weapons selected.`);

    return lines;
  }

  /**
   * Generates battle opener text.
   */
  static battleOpener(rng: IRNGService): string {
    const template = NarrativeTemplateEngine.getFromArchive(rng, ['pbp', 'openers']);
    return NarrativeTemplateEngine.interpolateTemplate(template, {});
  }

  /**
   * Narrates an attack (whiff).
   */
  static narrateAttack(
    rng: IRNGService,
    attackerName: string,
    weaponId?: string,
    _isMastery?: boolean
  ): string {
    const wName = getWeaponDisplayName(weaponId);
    const template = NarrativeTemplateEngine.getFromArchive(rng, ['pbp', 'whiffs']);
    return NarrativeTemplateEngine.interpolateTemplate(template, {
      attacker: attackerName,
      weapon: wName,
    });
  }

  /**
   * Narrates a passive style activation.
   */
  static narratePassive(rng: IRNGService, style: FightingStyle, actorName: string): string {
    const template = NarrativeTemplateEngine.getFromArchive(rng, ['passives', style]);
    return NarrativeTemplateEngine.interpolateTemplate(template, { attacker: actorName });
  }

  /**
   * Narrates a successful parry.
   */
  static narrateParry(rng: IRNGService, defenderName: string, weaponId?: string): string {
    const wName = getWeaponDisplayName(weaponId);
    const isShield =
      weaponId && ['small_shield', 'medium_shield', 'large_shield'].includes(weaponId);
    const type = isShield ? 'shield' : 'parry';

    const template = NarrativeTemplateEngine.getFromArchive(rng, [
      'pbp',
      'defenses',
      type,
      'success',
    ]);
    return NarrativeTemplateEngine.interpolateTemplate(template, {
      defender: defenderName,
      weapon: wName,
    });
  }

  /**
   * Narrates a successful dodge.
   */
  static narrateDodge(rng: IRNGService, defenderName: string): string {
    const template = NarrativeTemplateEngine.getFromArchive(rng, [
      'pbp',
      'defenses',
      'dodge',
      'success',
    ]);
    return NarrativeTemplateEngine.interpolateTemplate(template, { defender: defenderName });
  }

  /**
   * Narrates a counterstrike.
   */
  static narrateCounterstrike(rng: IRNGService, name: string): string {
    const template =
      NarrativeTemplateEngine.getFromArchive(rng, ['pbp', 'defenses', 'counterstrike']) ||
      '{{attacker}} counters!';
    return NarrativeTemplateEngine.interpolateTemplate(template, { attacker: name });
  }

  /**
   * Narrates a hit with severity tiers.
   */
  static narrateHit(
    rng: IRNGService,
    defenderName: string,
    location: string,
    _isMastery?: boolean,
    isSuperFlashy?: boolean,
    attackerName?: string,
    weaponId?: string,
    damage?: number,
    maxHp?: number,
    isFatal?: boolean,
    attackerFame?: number,
    isFavorite?: boolean
  ): string {
    const richLoc = this.richHitLocation(rng, location);
    const wName = getWeaponDisplayName(weaponId);
    const wType = getWeaponType(weaponId);

    const severity = this.getStrikeSeverity(
      damage || 0,
      maxHp || 100,
      isFatal || false,
      isSuperFlashy || false,
      isFavorite || false,
      attackerFame || 0
    );

    if (severity === 'critical_human' || severity === 'critical_supernatural') {
      audioManager.play('crit');
    }

    const template =
      NarrativeTemplateEngine.getFromArchive(rng, ['strikes', wType, severity]) ||
      NarrativeTemplateEngine.getFromArchive(rng, ['strikes', 'generic']);

    return NarrativeTemplateEngine.interpolateTemplate(template, {
      attacker: attackerName,
      defender: defenderName,
      weapon: wName,
      bodyPart: richLoc,
    });
  }

  /**
   * Narrates a parry break.
   */
  static narrateParryBreak(rng: IRNGService, attackerName: string, weaponId?: string): string {
    const wName = getWeaponDisplayName(weaponId);
    const template =
      NarrativeTemplateEngine.getFromArchive(rng, ['pbp', 'defenses', 'parry_break']) ||
      '{{attacker}} breaks the guard!';
    return NarrativeTemplateEngine.interpolateTemplate(template, {
      attacker: attackerName,
      weapon: wName,
    });
  }

  /**
   * Narrates initiative winner.
   */
  static narrateInitiative(
    rng: IRNGService,
    winnerName: string,
    isFeint: boolean,
    defenderName?: string
  ): string {
    const path = isFeint ? ['pbp', 'feints'] : ['pbp', 'initiative'];
    const template = NarrativeTemplateEngine.getFromArchive(rng, path);
    return NarrativeTemplateEngine.interpolateTemplate(template, {
      attacker: winnerName,
      defender: defenderName,
    });
  }

  /**
   * Narrates bout conclusion.
   */
  static narrateBoutEnd(
    rng: IRNGService,
    by: string,
    winnerName: string,
    loserName: string,
    weaponId?: string
  ): string[] {
    const wName = getWeaponDisplayName(weaponId);
    const wType = getWeaponType(weaponId);

    const categoryMap: Record<string, string> = {
      Kill: 'Kill',
      KO: 'KO',
      Stoppage: 'Stoppage',
      Exhaustion: 'Exhaustion',
    };

    const category = categoryMap[by] || 'KO';
    const conclusionPath = ['conclusions', category];
    const conclusion =
      NarrativeTemplateEngine.getFromArchive(rng, conclusionPath) ||
      '{{winner}} defeats {{loser}}.';
    const conclusionText = NarrativeTemplateEngine.interpolateTemplate(conclusion, {
      winner: winnerName,
      loser: loserName,
    });

    if (by === 'Kill') {
      const fatalBlowTemplate =
        NarrativeTemplateEngine.getFromArchive(rng, ['strikes', wType, 'fatal']) ||
        NarrativeTemplateEngine.getFromArchive(rng, ['strikes', 'generic']);
      const fatalBlow = NarrativeTemplateEngine.interpolateTemplate(fatalBlowTemplate, {
        attacker: winnerName,
        defender: loserName,
        weapon: wName,
      });
      return [fatalBlow, conclusionText];
    }

    return [conclusionText];
  }

  // Helper methods

  private static richHitLocation(rng: IRNGService, location: string): string {
    const hitLocations = (narrativeContent as NarrativeContent).pbp.hit_locations;
    const key = location.toLowerCase() as keyof typeof hitLocations;
    const variants = hitLocations[key];
    if (!variants) return location.toUpperCase();
    return rng.pick(variants);
  }

  private static getStrikeSeverity(
    damage: number,
    maxHp: number,
    isFatal: boolean,
    isCrit: boolean,
    isFavorite: boolean,
    fame: number
  ): 'glancing' | 'solid' | 'mastery' | 'critical_human' | 'critical_supernatural' | 'fatal' {
    if (isFatal) return 'fatal';

    const ratio = damage / maxHp;
    if (isCrit || ratio >= 0.25) {
      return fame >= 100 ? 'critical_supernatural' : 'critical_human';
    }

    if (isFavorite) return 'mastery';

    if (ratio >= 0.1) return 'solid';
    return 'glancing';
  }
}

// Export static methods as standalone functions for backward compatibility
export const generateWarriorIntro = CombatNarrator.generateWarriorIntro.bind(CombatNarrator);
export const battleOpener = CombatNarrator.battleOpener.bind(CombatNarrator);
export const narrateAttack = CombatNarrator.narrateAttack.bind(CombatNarrator);
export const narratePassive = CombatNarrator.narratePassive.bind(CombatNarrator);
export const narrateParry = CombatNarrator.narrateParry.bind(CombatNarrator);
export const narrateDodge = CombatNarrator.narrateDodge.bind(CombatNarrator);
export const narrateCounterstrike = CombatNarrator.narrateCounterstrike.bind(CombatNarrator);
export const narrateHit = CombatNarrator.narrateHit.bind(CombatNarrator);
export const narrateParryBreak = CombatNarrator.narrateParryBreak.bind(CombatNarrator);
export const narrateInitiative = CombatNarrator.narrateInitiative.bind(CombatNarrator);
export const narrateBoutEnd = CombatNarrator.narrateBoutEnd.bind(CombatNarrator);

/**
 * Narrative Combat - Combat narration functions
 * Extracted from narrativePBP.ts to follow SRP
 */
import type { FightingStyle } from '@/types/shared.types';
import { getWeaponDisplayName, getWeaponType, pick } from './narrativeUtils';
import {
  getFromArchive,
  interpolateTemplate,
  richHitLocation,
  getStrikeSeverity,
} from './narrativePBPUtils';
import { audioManager } from '@/lib/AudioManager';

type RNG = () => number;

/**
 * Narrates an attack/whiff.
 */
export function narrateAttack(
  rng: RNG,
  attackerName: string,
  weaponId?: string,
  isMastery?: boolean,
  defenderName?: string
): string {
  const wName = getWeaponDisplayName(weaponId);
  const template = getFromArchive(rng, ['pbp', 'whiffs']);
  return interpolateTemplate(template, {
    attacker: attackerName,
    defender: defenderName,
    weapon: wName,
  });
}

/**
 * Narrates a passive ability activation.
 */
export function narratePassive(rng: RNG, style: FightingStyle, actorName: string): string {
  const template = getFromArchive(rng, ['passives', style]);
  return interpolateTemplate(template, { attacker: actorName });
}

/**
 * Narrates a successful parry.
 */
export function narrateParry(rng: RNG, defenderName: string, weaponId?: string): string {
  const wName = getWeaponDisplayName(weaponId);
  const isShield = weaponId && ['small_shield', 'medium_shield', 'large_shield'].includes(weaponId);
  const type = isShield ? 'shield' : 'parry';

  const template = getFromArchive(rng, ['pbp', 'defenses', type, 'success']);
  return interpolateTemplate(template, { defender: defenderName, weapon: wName });
}

/**
 * Narrates a successful dodge.
 */
export function narrateDodge(rng: RNG, defenderName: string): string {
  const template = getFromArchive(rng, ['pbp', 'defenses', 'dodge', 'success']);
  return interpolateTemplate(template, { defender: defenderName });
}

/**
 * Narrates a counterstrike.
 */
export function narrateCounterstrike(rng: RNG, name: string): string {
  const template =
    getFromArchive(rng, ['pbp', 'defenses', 'counterstrike']) || '{{attacker}} counters!';
  return interpolateTemplate(template, { attacker: name });
}

/**
 * Narrates a hit with severity-based flavor.
 */
export function narrateHit(
  rng: RNG,
  defenderName: string,
  location: string,
  isMastery?: boolean,
  isSuperFlashy?: boolean,
  attackerName?: string,
  weaponId?: string,
  damage?: number,
  maxHp?: number,
  isFatal?: boolean,
  attackerFame?: number,
  isFavorite?: boolean
): string {
  const richLoc = richHitLocation(rng, location);
  const wName = getWeaponDisplayName(weaponId);
  const wType = getWeaponType(weaponId);

  const severity = getStrikeSeverity(
    damage || 0,
    maxHp || 100,
    isFatal || false,
    isSuperFlashy || false,
    isFavorite || false,
    attackerFame || 0
  );

  if (severity === 'critical_human' || severity === 'critical_supernatural') {
    audioManager.play('crit');
  }

  let template = '';
  if (isFatal) {
    template = getFromArchive(rng, ['pbp', 'executions']);
  }

  if (!template || template === 'A fierce exchange occurs.') {
    template = getFromArchive(rng, ['strikes', wType, severity]);
  }

  if (!template || template === 'A fierce exchange occurs.') {
    template =
      getFromArchive(rng, ['strikes', 'generic']) ||
      getFromArchive(rng, ['pbp', 'hits', 'generic']);
  }

  return interpolateTemplate(template, {
    attacker: attackerName,
    defender: defenderName,
    weapon: wName,
    bodyPart: richLoc,
  });
}

/**
 * Narrates a broken parry.
 */
export function narrateParryBreak(rng: RNG, attackerName: string, weaponId?: string): string {
  const wName = getWeaponDisplayName(weaponId);
  const template =
    getFromArchive(rng, ['pbp', 'defenses', 'parry_break']) || '{{attacker}} breaks the guard!';
  return interpolateTemplate(template, { attacker: attackerName, weapon: wName });
}

/**
 * Narrates initiative win.
 */
export function narrateInitiative(
  rng: RNG,
  winnerName: string,
  isFeint: boolean,
  defenderName?: string
): string {
  const path = isFeint ? ['pbp', 'feints'] : ['pbp', 'initiative'];
  const template = getFromArchive(rng, path);
  return interpolateTemplate(template, { attacker: winnerName, defender: defenderName });
}

/**
 * Narrative Intro - Pre-bout introduction functions
 * Extracted from narrativePBP.ts to follow SRP
 */
import { type FightingStyle, STYLE_DISPLAY_NAMES } from '@/types/shared.types';
import { getItemById, checkWeaponRequirements, type EquipmentItem } from '@/data/equipment';
import type { Attributes } from '@/types/shared.types';
import { szToHeight, getWeaponDisplayName } from './narrativeUtils';
import { getFromArchive, interpolateTemplate, type CombatContext } from './narrativePBPUtils';

type RNG = () => number;

export interface WarriorIntroData {
  name: string;
  style: FightingStyle;
  weaponId?: string;
  armorId?: string;
  helmId?: string;
  height?: number;
  /** Physical attributes — used by the weapon-fit statement to call out deficiencies. */
  attributes?: Attributes;
  /** Optional handedness override (deterministic) — when absent, RNG chooses per-warrior. */
  handedness?: 'right' | 'left' | 'ambidextrous';
  /** Backup weapon shown in intro — minor flavour, purely cosmetic. */
  backupWeaponId?: string;
}

/**
 * Generates warrior introduction text.
 */
export function generateWarriorIntro(rng: RNG, data: WarriorIntroData, sz?: number): string[] {
  const lines: string[] = [];
  const n = data.name;

  if (sz) lines.push(`${n} is ${szToHeight(sz)}.`);

  // Handedness: deterministic override wins; otherwise RNG biased right-handed.
  const hand = data.handedness
    ? data.handedness === 'ambidextrous'
      ? 'ambidextrous'
      : `${data.handedness} handed`
    : rng() < 0.85
      ? 'right handed'
      : rng() < 0.5
        ? 'left handed'
        : 'ambidextrous';
  lines.push(`${n} is ${hand}.`);

  // Armor & Helm
  const armorItem = data.armorId ? getItemById(data.armorId) : null;
  if (armorItem && armorItem.id !== 'none_armor') {
    const verb = getFromArchive(rng, ['fanfare', 'armor_intro_verbs']) || 'is wearing';
    lines.push(`${n} ${verb} ${armorItem.name.toUpperCase()} armor.`);
  } else {
    lines.push(`${n} has chosen to fight without body armor.`);
  }

  const helmItem = data.helmId ? getItemById(data.helmId) : null;
  if (helmItem && helmItem.id !== 'none_helm') {
    lines.push(`And will wear a ${helmItem.name.toUpperCase()}.`);
  }

  // Weapon & Style
  const weaponName = getWeaponDisplayName(data.weaponId);
  if (weaponName === 'OPEN HAND') {
    lines.push(`${n} will fight using his OPEN HAND.`);
  } else {
    const verb =
      getFromArchive(rng, ['fanfare', 'weapon_intro_verbs']) || 'is armed with {{weapon}}';
    lines.push(interpolateTemplate(verb, { attacker: n, weapon: weaponName }));
  }

  lines.push(`${n} uses the ${STYLE_DISPLAY_NAMES[data.style]} style.`);

  // Weapon-fitness statement — compares warrior attributes against weapon's
  // canonical ST/SZ/WT/DF minimums. Falls back to the generic line when we
  // don't have attributes (e.g. generated freelancers without stats).
  const weaponItem: EquipmentItem | undefined = data.weaponId
    ? getItemById(data.weaponId)
    : undefined;
  if (data.attributes && weaponItem && weaponItem.id !== 'open_hand') {
    const fit = checkWeaponRequirements(weaponItem.id, data.attributes);
    if (fit.attPenalty < 0) {
      lines.push(`${n} strains against the ${weaponItem.name} — ill-suited to its demands.`);
    } else {
      lines.push(`${n} is well suited to the ${weaponItem.name}.`);
    }
  } else {
    lines.push(`${n} is well suited to the weapons selected.`);
  }

  // Backup weapon mention — flavour only, surfaced when present.
  const backupItem = data.backupWeaponId ? getItemById(data.backupWeaponId) : undefined;
  if (backupItem && backupItem.id !== 'none_backup' && backupItem.id !== 'open_hand') {
    lines.push(`${n} carries a ${backupItem.name} as backup.`);
  }

  return lines;
}

/**
 * Generates battle opener text.
 */
export function battleOpener(rng: RNG): string {
  return getFromArchive(rng, ['pbp', 'openers']);
}

/**
 * Narrative PBP Utils - Core utility functions for narrative generation
 * Extracted from narrativePBP.ts to follow SRP
 */
import narrativeContent from '@/data/narrativeContent.json';
import type { NarrativeContent } from '@/types/narrative.types';
import type { IRNGService } from '@/engine/core/rng/IRNGService';
import { pick } from './narrativeUtils';

type RNG = () => number;

export interface CombatContext {
  attacker?: string;
  defender?: string;
  name?: string;
  weapon?: string;
  bodyPart?: string;
  hits?: string | number;
}

/**
 * Replaces canonical tokens (%A, %D, %W, %BP, %H) with contextual values.
 */
export function interpolateTemplate(template: string, ctx: CombatContext): string {
  if (!template) return 'No description available.';
  let result = template
    .replace(/%A/g, ctx.attacker || ctx.name || 'The warrior')
    .replace(/%D/g, ctx.defender || 'the opponent')
    .replace(/%W/g, ctx.weapon || 'weapon')
    .replace(/%BP/g, ctx.bodyPart || 'body')
    .replace(/%H/g, String(ctx.hits || ''));

  // Also support Handlebars-style placeholders
  for (const [key, value] of Object.entries(ctx)) {
    if (value !== undefined) {
      result = result.replace(new RegExp(`\\{\\{\\s*${key}\\s*\\}\\}`, 'g'), String(value));
    }
  }

  // Fallbacks for specific templates that use {{name}} but only pass attacker/defender
  if (ctx.attacker && !ctx.name) {
    result = result.replace(/\{\{\s*name\s*\}\}/g, String(ctx.attacker));
  } else if (ctx.name && !ctx.attacker) {
    result = result.replace(/\{\{\s*attacker\s*\}\}/g, String(ctx.name));
  }

  return result;
}

/**
 * Maps damage/health ratio to mechanical severity categories.
 * Supports the expanded 6-tier Strike system.
 */
export function getStrikeSeverity(
  damage: number,
  maxHp: number,
  isFatal: boolean,
  isCrit: boolean,
  isFavorite: boolean,
  fame: number
): 'glancing' | 'solid' | 'mastery' | 'critical_human' | 'critical_supernatural' | 'fatal' {
  if (isFatal) return 'fatal';

  const ratio = damage / maxHp;
  if (isCrit || ratio >= 0.25) {
    return fame >= 100 ? 'critical_supernatural' : 'critical_human';
  }

  if (isFavorite) return 'mastery';

  if (ratio >= 0.1) return 'solid';
  return 'glancing';
}

/**
 * Quietly walk the archive to see if the given path resolves to a non-empty
 * string array. Returns the array (or null) without logging — intended for
 * tiered lookups where misses at lower specificity are expected.
 */
export function peekArchive(path: string[]): string[] | null {
  let current: unknown = narrativeContent;
  for (const key of path) {
    if (current && typeof current === 'object' && key in (current as Record<string, unknown>)) {
      current = (current as Record<string, unknown>)[key];
    } else {
      return null;
    }
  }
  if (Array.isArray(current) && current.length > 0) return current as string[];
  return null;
}

/**
 * Safely picks a template from the JSON archive or returns a generic fallback.
 * Supports both RNG function and IRNGService objects.
 */
export function getFromArchive(rng: RNG | IRNGService, path: string[]): string {
  try {
    let current: unknown = narrativeContent;
    for (const key of path) {
      if (current && typeof current === 'object' && key in current) {
        current = (current as Record<string, unknown>)[key];
      } else {
        throw new Error(`Invalid path: ${key}`);
      }
    }
    if (Array.isArray(current) && current.length > 0) {
      const rngFn = typeof rng === 'function' ? rng : () => rng.next();
      return pick(rngFn, current);
    }
  } catch (e) {
    console.error(`Narrative Archive Error: Missing path ${path.join('.')}`);
  }
  return 'A fierce exchange occurs.';
}

/**
 * Gets rich hit location description.
 */
export function richHitLocation(rng: RNG, location: string): string {
  const hitLocations = (narrativeContent as NarrativeContent).pbp.hit_locations;
  const key = location.toLowerCase() as keyof typeof hitLocations;
  const variants = hitLocations[key];
  if (!variants) return location.toUpperCase();
  return pick(rng, variants);
}

/**
 * Narrative Post-Bout - Post-bout narration functions
 * Extracted from narrativePBP.ts to follow SRP
 */
import { getWeaponDisplayName, getWeaponType, pick } from './narrativeUtils';
import { getFromArchive, interpolateTemplate, peekArchive } from './narrativePBPUtils';
import { audioManager } from '@/lib/AudioManager';

type RNG = () => number;

/**
 * Narrates bout end.
 */
/**
 * Optional context for data-driven kill-text assembly. When `cause`/`style`/`mood`
 * are supplied, the narrator prefers tiered archive paths (see below) before
 * falling back to generic conclusions. All fields are optional — legacy callers
 * keep working unchanged.
 */
export interface BoutEndContext {
  cause?: string; // DeathCauseBucket: EXECUTION | CRITICAL_CHAIN | ARMOR_FAILURE | FATIGUE_COLLAPSE | RIVALRY_FINISH | FATAL_DAMAGE
  style?: string; // Winner's fighting style — drives tonal selection (e.g. AimedBlow → "precise")
  mood?: string; // CrowdMood — Calm/Bloodthirsty/Theatrical/Solemn/Festive
}

// Map DeathCauseBucket → archive subpath. Missing paths fall through to generic.
const CAUSE_ARCHIVE_PATH: Record<string, string> = {
  EXECUTION: 'execution',
  CRITICAL_CHAIN: 'critical_chain',
  ARMOR_FAILURE: 'armor_failure',
  FATIGUE_COLLAPSE: 'fatigue_collapse',
  RIVALRY_FINISH: 'rivalry_finish',
  FATAL_DAMAGE: 'fatal_damage',
};

export function narrateBoutEnd(
  rng: RNG,
  by: string,
  winnerName: string,
  loserName: string,
  weaponId?: string,
  ctx: BoutEndContext = {}
): string[] {
  const wName = getWeaponDisplayName(weaponId);
  const wType = getWeaponType(weaponId);

  const categoryMap: Record<string, string> = {
    Kill: 'Kill',
    KO: 'KO',
    Stoppage: 'Stoppage',
    Exhaustion: 'Exhaustion',
  };

  const cat = categoryMap[by] || 'KO';
  const conclusionTemplate = getFromArchive(rng, ['conclusions', cat]);
  const conclusion = interpolateTemplate(conclusionTemplate, {
    attacker: winnerName,
    defender: loserName,
    weapon: wName,
  });

  if (cat === 'Kill') audioManager.play('death');

  if (cat === 'Kill') {
    // Tiered lookup for kill-text:
    //   1) kill_text.<cause>.<style>.<mood>  (most specific)
    //   2) kill_text.<cause>.<style>
    //   3) kill_text.<cause>
    //   4) strikes.<weaponType>.fatal        (legacy weapon-first path)
    //   5) strikes.generic                   (ultimate fallback)
    // Each tier only fires if the archive returns a non-fallback line.
    const causeSlug = ctx.cause ? CAUSE_ARCHIVE_PATH[ctx.cause] : undefined;
    const styleSlug = ctx.style ? ctx.style.toLowerCase() : undefined;
    const moodSlug = ctx.mood ? ctx.mood.toLowerCase() : undefined;

    const candidatePaths: string[][] = [];
    if (causeSlug && styleSlug && moodSlug)
      candidatePaths.push(['kill_text', causeSlug, styleSlug, moodSlug]);
    if (causeSlug && styleSlug) candidatePaths.push(['kill_text', causeSlug, styleSlug]);
    if (causeSlug) candidatePaths.push(['kill_text', causeSlug]);
    candidatePaths.push(['strikes', wType, 'fatal']);
    candidatePaths.push(['strikes', 'generic']);

    let fatalBlowTemplate = '';
    const fallbackMarker = 'A fierce exchange occurs.';
    for (const path of candidatePaths) {
      // Silent peek first — avoids console.error spam for expected misses in
      // the tiered cause/style/mood cascade.
      const pool = peekArchive(path);
      if (pool && pool.length > 0) {
        fatalBlowTemplate = getFromArchive(rng, path);
        if (fatalBlowTemplate && fatalBlowTemplate !== fallbackMarker) break;
      }
    }
    if (!fatalBlowTemplate) fatalBlowTemplate = fallbackMarker;

    const fatalBlow = interpolateTemplate(fatalBlowTemplate, {
      attacker: winnerName,
      defender: loserName,
      weapon: wName,
    });
    return [fatalBlow, conclusion];
  }

  return [conclusion];
}

/**
 * Generates popularity line.
 */
export function popularityLine(rng: RNG, name: string, popDelta: number): string | null {
  const cat = popDelta >= 3 ? 'great' : popDelta >= 1 ? 'normal' : '';
  if (!cat) return null;
  const template = getFromArchive(rng, ['pbp', 'meta', 'popularity', cat]);
  return interpolateTemplate(template, { name });
}

/**
 * Generates skill learn line.
 */
export function skillLearnLine(rng: RNG, name: string): string {
  const template = getFromArchive(rng, ['pbp', 'meta', 'skill_learns']);
  return interpolateTemplate(template, { attacker: name });
}

/**
 * Generates trading blows line.
 */
export function tradingBlowsLine(rng: RNG): string {
  return getFromArchive(rng, ['pbp', 'pacing', 'trading_blows']);
}

/**
 * Generates stalemate line.
 */
export function stalemateLine(rng: RNG): string {
  return getFromArchive(rng, ['pbp', 'pacing', 'stalemate']);
}

/**
 * Generates taunt line.
 */
export function tauntLine(rng: RNG, name: string, isWinner: boolean): string | null {
  // Fire ~40% of the time (was 20%) — taunts are flavour, not signal, so they
  // should feel present rather than rare. Winners taunt more than losers.
  const threshold = isWinner ? 0.45 : 0.3;
  if (rng() > threshold) return null;
  const cat = isWinner ? 'winner' : 'loser';
  const template = getFromArchive(rng, ['pbp', 'taunts', cat]);
  return interpolateTemplate(template, { attacker: name });
}

/**
 * Generates conserving line.
 */
export function conservingLine(name: string): string {
  return `${name} is conserving his energy.`;
}

import narrativeContent from '@/data/narrativeContent.json';
import type { IRNGService } from '@/engine/core/rng/IRNGService';

export interface CombatContext {
  attacker?: string;
  defender?: string;
  name?: string;
  weapon?: string;
  bodyPart?: string;
  hits?: string | number;
  winner?: string;
  loser?: string;
}

/**
 * NarrativeTemplateEngine - Template interpolation and archive access.
 * Handles all narrative content retrieval and token replacement.
 */
export class NarrativeTemplateEngine {
  private constructor() {}
  /**
   * Replaces canonical tokens (%A, %D, %W, %BP, %H) with contextual values.
   */
  static interpolateTemplate(template: string, ctx: CombatContext): string {
    if (!template) return 'No description available.';
    let result = template
      .replace(/%A/g, ctx.attacker || ctx.name || 'The warrior')
      .replace(/%D/g, ctx.defender || 'the opponent')
      .replace(/%W/g, ctx.weapon || 'weapon')
      .replace(/%BP/g, ctx.bodyPart || 'body')
      .replace(/%H/g, String(ctx.hits || ''))
      .replace(/%WINNER/g, ctx.winner || 'the winner')
      .replace(/%LOSER/g, ctx.loser || 'the loser');

    // Also handle {{token}} format
    result = result
      .replace(/\{\{attacker\}\}/g, ctx.attacker || ctx.name || 'The warrior')
      .replace(/\{\{defender\}\}/g, ctx.defender || 'the opponent')
      .replace(/\{\{weapon\}\}/g, ctx.weapon || 'weapon')
      .replace(/\{\{bodyPart\}\}/g, ctx.bodyPart || 'body')
      .replace(/\{\{name\}\}/g, ctx.name || 'The warrior')
      .replace(/\{\{winner\}\}/g, ctx.winner || 'the winner')
      .replace(/\{\{loser\}\}/g, ctx.loser || 'the loser');

    return result;
  }

  /**
   * Safely picks a template from the JSON archive or returns a generic fallback.
   */
  static getFromArchive(rng: IRNGService, path: string[]): string {
    try {
      let current: unknown = narrativeContent;
      for (const key of path) {
        if (current && typeof current === 'object' && key in current) {
          current = (current as Record<string, unknown>)[key];
        } else {
          throw new Error(`Invalid path: ${key}`);
        }
      }
      if (Array.isArray(current) && current.length > 0) {
        return rng.pick(current);
      }
    } catch (e) {
      console.error(`Narrative Archive Error: Missing path ${path.join('.')}`);
    }
    return 'A fierce exchange occurs.'; // Ultimate fallback
  }
}

import { NarrativeTemplateEngine } from './narrativeTemplateEngine';
import type { IRNGService } from '@/engine/core/rng/IRNGService';

/**
 * StatusNarrator - Damage, fatigue, state change, and crowd reaction narration.
 * Handles all status-related narrative generation.
 */
export class StatusNarrator {
  private constructor() {}
  /**
   * Generates damage severity line based on damage ratio.
   */
  static damageSeverityLine(rng: IRNGService, damage: number, maxHp: number): string | null {
    const ratio = damage / maxHp;
    if (ratio >= 0.35) {
      const template = NarrativeTemplateEngine.getFromArchive(rng, [
        'pbp',
        'damage_severity',
        'deadly',
      ]);
      if (!template) return null;
      const templateStr = Array.isArray(template) ? template[0] : template;
      return NarrativeTemplateEngine.interpolateTemplate(templateStr, {});
    }
    if (ratio >= 0.25) {
      const template = NarrativeTemplateEngine.getFromArchive(rng, [
        'pbp',
        'damage_severity',
        'terrific',
      ]);
      if (!template) return null;
      const templateStr = Array.isArray(template) ? template[0] : template;
      return NarrativeTemplateEngine.interpolateTemplate(templateStr, {});
    }
    if (ratio >= 0.15) {
      const template = NarrativeTemplateEngine.getFromArchive(rng, [
        'pbp',
        'damage_severity',
        'powerful',
      ]);
      if (!template) return null;
      const templateStr = Array.isArray(template) ? template[0] : template;
      return NarrativeTemplateEngine.interpolateTemplate(templateStr, {});
    }
    if (ratio <= 0.05) {
      const template = NarrativeTemplateEngine.getFromArchive(rng, [
        'pbp',
        'damage_severity',
        'glancing',
      ]);
      if (!template) return null;
      const templateStr = Array.isArray(template) ? template[0] : template;
      return NarrativeTemplateEngine.interpolateTemplate(templateStr, {});
    }
    return null;
  }

  /**
   * Generates state change line when HP drops below thresholds.
   */
  static stateChangeLine(
    rng: IRNGService,
    name: string,
    hpRatio: number,
    prevHpRatio: number
  ): string | null {
    let cat = '';
    if (hpRatio <= 0.2 && prevHpRatio > 0.2) cat = 'severe';
    else if (hpRatio <= 0.4 && prevHpRatio > 0.4) cat = 'desperate';
    else if (hpRatio <= 0.6 && prevHpRatio > 0.6) cat = 'serious';

    if (cat) {
      const template = NarrativeTemplateEngine.getFromArchive(rng, ['pbp', 'status_changes', cat]);
      if (!template) return null;
      // Handle case where template might be an array
      const templateStr = Array.isArray(template) ? template[0] : template;
      return NarrativeTemplateEngine.interpolateTemplate(templateStr, { name });
    }
    return null;
  }

  /**
   * Generates fatigue line when endurance is low.
   */
  static fatigueLine(rng: IRNGService, name: string, endRatio: number): string | null {
    if (endRatio <= 0.15) return `${name} is tired and barely able to defend himself!`;
    if (endRatio <= 0.3) return `${name} is breathing heavily.`;
    return null;
  }

  /**
   * Generates crowd reaction line.
   */
  static crowdReaction(
    rng: IRNGService,
    loserName: string,
    winnerName: string,
    hpRatio: number
  ): string | null {
    if (rng.next() > 0.25) return null;
    const mood = hpRatio <= 0.3 ? 'encourage' : rng.next() < 0.5 ? 'negative' : 'positive';
    const template = NarrativeTemplateEngine.getFromArchive(rng, ['pbp', 'reactions', mood]);
    if (!template) return null;
    // Handle case where template might be an array
    const templateStr = Array.isArray(template) ? template[0] : template;
    return NarrativeTemplateEngine.interpolateTemplate(templateStr, { name: loserName });
  }

  /**
   * Generates minute status line showing who's winning.
   */
  static minuteStatusLine(
    rng: IRNGService,
    minute: number,
    nameA: string,
    nameD: string,
    hitsA: number,
    hitsD: number
  ): string {
    if (hitsA > hitsD + 3) return `${nameA} is beating his opponent!`;
    if (hitsD > hitsA + 3) return `${nameD} is beating his opponent!`;
    const template = NarrativeTemplateEngine.getFromArchive(rng, ['pbp', 'pacing', 'stalemate']);
    if (!template) return 'The bout is evenly matched.';
    // Handle case where template might be an array
    const templateStr = Array.isArray(template) ? template[0] : template;
    return NarrativeTemplateEngine.interpolateTemplate(templateStr, {});
  }

  /**
   * Generates popularity gain line.
   */
  static popularityLine(rng: IRNGService, name: string, popDelta: number): string | null {
    const cat = popDelta >= 3 ? 'great' : popDelta >= 1 ? 'normal' : '';
    if (!cat) return null;
    const template = NarrativeTemplateEngine.getFromArchive(rng, [
      'pbp',
      'meta',
      'popularity',
      cat,
    ]);
    return NarrativeTemplateEngine.interpolateTemplate(template, { name });
  }

  /**
   * Generates skill learn line.
   */
  static skillLearnLine(rng: IRNGService, name: string): string {
    const template = NarrativeTemplateEngine.getFromArchive(rng, ['pbp', 'meta', 'skill_learns']);
    if (!template) return 'A fierce exchange occurs.';
    // Handle case where template might be an array
    const templateStr = Array.isArray(template) ? template[0] : template;
    return NarrativeTemplateEngine.interpolateTemplate(templateStr, { attacker: name });
  }

  /**
   * Generates trading blows line.
   */
  static tradingBlowsLine(rng: IRNGService): string {
    const template = NarrativeTemplateEngine.getFromArchive(rng, [
      'pbp',
      'pacing',
      'trading_blows',
    ]);
    if (!template) return 'A fierce exchange occurs.';
    const templateStr = Array.isArray(template) ? template[0] : template;
    return NarrativeTemplateEngine.interpolateTemplate(templateStr, {});
  }

  /**
   * Generates stalemate line.
   */
  static stalemateLine(rng: IRNGService): string {
    const template = NarrativeTemplateEngine.getFromArchive(rng, ['pbp', 'pacing', 'stalemate']);
    if (!template) return 'A fierce exchange occurs.';
    const templateStr = Array.isArray(template) ? template[0] : template;
    return NarrativeTemplateEngine.interpolateTemplate(templateStr, {});
  }

  /**
   * Generates taunt line.
   */
  static tauntLine(rng: IRNGService, name: string, isWinner: boolean): string | null {
    if (rng.next() > 0.2) return null;
    const cat = isWinner ? 'winner' : 'loser';
    const template = NarrativeTemplateEngine.getFromArchive(rng, ['pbp', 'taunts', cat]);
    if (!template) return null;
    // Handle case where template might be an array
    const templateStr = Array.isArray(template) ? template[0] : template;
    return NarrativeTemplateEngine.interpolateTemplate(templateStr, { attacker: name });
  }

  /**
   * Generates conserving energy line.
   */
  static conservingLine(name: string): string {
    return `${name} is conserving his energy.`;
  }

  /**
   * Generates pressing attack line.
   */
  static pressingLine(rng: IRNGService, name: string): string {
    const template = NarrativeTemplateEngine.getFromArchive(rng, ['pbp', 'pacing', 'pressing']);
    if (!template) return 'A fierce exchange occurs.';
    const templateStr = Array.isArray(template) ? template[0] : template;
    return NarrativeTemplateEngine.interpolateTemplate(templateStr, { attacker: name });
  }

  /**
   * Generates insight hint line.
   */
  static narrateInsightHint(rng: IRNGService, attribute: string): string | null {
    const template = NarrativeTemplateEngine.getFromArchive(rng, ['pbp', 'insights', attribute]);
    if (!template || template === 'A fierce exchange occurs.') return null;
    // Handle case where template might be an array
    const templateStr = Array.isArray(template) ? template[0] : template;
    return NarrativeTemplateEngine.interpolateTemplate(templateStr, {});
  }
}

